function base64url(data) {
  return Buffer.from(data).toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');
}
function createJWT(creds, scope) {
  const now = Math.floor(Date.now() / 1000);
  const header = base64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }));
  const payload = base64url(JSON.stringify({ iss: creds.client_email, scope, aud: 'https://oauth2.googleapis.com/token', exp: now + 3600, iat: now }));
  const sign = crypto.createSign('RSA-SHA256');
  sign.update(header + '.' + payload);
  return header + '.' + payload + '.' + base64url(sign.sign(creds.private_key));
}
async function getToken() {
